n = int(input())
p = list(map(int, input().split()))
p_max = int(input())

dp = [[0 for i in range(p_max + 1)] for j in range(n + 1)]

for i in range(n + 1):
    for j in range(p_max + 1):
        if i == 0 or j == 0:
            continue

        if p[i - 1] > j:
            dp[i][j] = dp[i - 1][j]
        else:
            dp[i][j] = max(dp[i - 1][j], p[i - 1] + dp[i - 1][j - p[i - 1]])

print(dp[n][p_max])
